board.setVar("tmp_selected_arc", "");
board.setVar("tmp_selected_beat", "");
board.setVar("tmp_route_arc", "");
board.setVar("tmp_current_arc", "");
board.setVar("tmp_story_intent", "continue");
board.setVar("tmp_story_pace", "normal");
board.setVar("tmp_story_allow_skip", false);
board.setVar("tmp_answer_progress", false);

function latestUserText() {
  const msgs = board.channel(board.MAIN_CHANNEL) || [];
  for (let i = msgs.length - 1; i >= 0; i--) {
    const msg = msgs[i] || {};
    if (msg.role !== "user") continue;
    if (typeof msg.content === "string" && msg.content.trim()) return msg.content.trim();
    const parts = Array.isArray(msg.parts) ? msg.parts : [];
    const text = parts.map(function(part) {
      return part && part.type === "text" && typeof part.text === "string" ? part.text : "";
    }).join("").trim();
    if (text) return text;
  }
  return "";
}
board.setChannel("story_route_channel", [{
  role: "user",
  parts: [{ type: "text", text: latestUserText() }],
}]);
board.setVar("tmp_needs_match_route", true);

var answerProgress = board.getVar("tmp_answer_progress") === true;
var intent = String(board.getVar("tmp_story_intent") || "continue");
var pace = String(board.getVar("tmp_story_pace") || "normal");
var allowSkip = board.getVar("tmp_story_allow_skip") !== false;

var directive = [];
if (answerProgress) {
  directive.push("Briefly answer where the story currently is using story_progress_state, then complete target_beat. Do not narrate locked_before again.");
} else if (intent === "side_question") {
  directive.push("Answer the user's side question briefly, then complete target_beat. Do not narrate locked_before again.");
} else if (intent === "start") {
  directive.push("Begin this story arc by completing target_beat.");
} else {
  directive.push("Continue by completing target_beat from story_progress_state. Treat locked_before as already completed.");
}
if (pace === "slow" || !allowSkip) {
  directive.push("Use small steps and do not skip intermediate events.");
} else {
  directive.push("Keep a natural pace, but do not summarize the whole arc.");
}
board.setVar("tmp_story_control_directive", directive.join(" "));

function parsedField(raw, field, allowed, fallback) {
  var re = new RegExp("(^|[\\s;,-])" + field + "\\s*=\\s*([^;\\s]+)", "i");
  var match = re.exec(String(raw || ""));
  var value = match ? String(match[2] || "").toLowerCase() : "";
  for (var i = 0; i < allowed.length; i++) {
    if (value === allowed[i]) return value;
  }
  return fallback;
}
function parsedRouteArc(raw) {
  var match = /(^|\s)route_arc\s*=\s*(none|origin|heaven|pilgrimage|trials|kingdoms|arrival)\b/i.exec(String(raw || ""));
  return match ? match[2].toLowerCase() : "none";
}
function parsedRouteBeat(raw) {
  var match = /(^|\s)route_beat\s*=\s*([a-z]+(?:_[a-z]+)?\.[a-z0-9_]+|none)\b/i.exec(String(raw || ""));
  var beat = match ? match[2].toLowerCase() : "none";
  var allowed = {
    "origin.birth": true,
    "origin.waterfall": true,
    "origin.king": true,
    "origin.longevity": true,
    "origin.depart": true,
    "origin.find_master": true,
    "origin.name": true,
    "origin.practice": true,
    "origin.learn_immortality": true,
    "origin.learn_transform": true,
    "origin.cloud": true,
    "origin.expelled": true,
    "origin.return_home": true,
    "origin.demon": true,
    "origin.dragon_palace": true,
    "origin.underworld": true,
    "heaven.summoned": true,
    "heaven.bimawen": true,
    "heaven.qitian": true,
    "heaven.peaches": true,
    "heaven.capture": true,
    "heaven.furnace": true,
    "heaven.wuxing_mountain": true,
    "pilgrimage.rescue": true,
    "pilgrimage.tight_band": true,
    "pilgrimage.white_dragon": true,
    "pilgrimage.bajie": true,
    "pilgrimage.shaseng": true,
    "trials.white_bone": true,
    "trials.exile": true,
    "trials.return_trust": true,
    "kingdoms.daughter_river": true,
    "kingdoms.daughter_queen": true,
    "kingdoms.scorpion": true,
    "kingdoms.chechi": true,
    "kingdoms.biqiu": true,
    "kingdoms.lion_camel": true,
    "arrival.flame_mountain": true,
    "arrival.borrow_fan": true,
    "arrival.near_lingshan": true,
    "arrival.scriptures": true,
    "arrival.river_drop": true,
    "arrival.complete": true,
  };
  return allowed[beat] ? beat : "none";
}

var raw = String(board.getVar("tmp_story_route_text") || "");
var intent = parsedField(raw, "intent", ["start", "continue", "progress_question", "side_question", "reroute"], "continue");
var pace = parsedField(raw, "pace", ["normal", "slow"], "normal");
var allowSkipText = parsedField(raw, "allow_skip", ["true", "false"], "true");
var answerProgressText = parsedField(raw, "answer_progress", ["true", "false"], intent === "progress_question" ? "true" : "false");
var arc = parsedRouteArc(raw);
var beat = parsedRouteBeat(raw);
if (beat !== "none" && arc === "none") arc = beat.split(".")[0];
var currentState = board.getVar("story_progress_state") || {};
var currentArc = String(currentState.arc || board.getVar("current_arc") || "");
if (beat === "none" && arc !== "none" && arc === currentArc) {
  arc = "none";
}
if (arc !== "none" || beat !== "none") intent = "reroute";
board.setVar("tmp_story_intent", intent);
board.setVar("tmp_story_pace", pace);
board.setVar("tmp_story_allow_skip", allowSkipText === "true");
board.setVar("tmp_answer_progress", answerProgressText === "true");
board.setVar("tmp_route_beat", beat === "none" ? "" : beat);
if (arc === "none") {
  board.setVar("tmp_route_arc", "");
  board.setVar("tmp_route_action", "accept");
} else {
  board.setVar("tmp_route_arc", arc);
  board.setVar("tmp_route_action", "cancel");
}

parallel.cancelNode("storyteller_origin", "story route changed");
parallel.cancelNode("storyteller_heaven", "story route changed");
parallel.cancelNode("storyteller_pilgrimage", "story route changed");
parallel.cancelNode("storyteller_trials", "story route changed");
parallel.cancelNode("storyteller_kingdoms", "story route changed");
parallel.cancelNode("storyteller_arrival", "story route changed");
board.setVar("tmp_reroute_arc", String(board.getVar("tmp_route_arc") || "origin"));

function storyNode(arc) {
  var nodes = {
    origin: "storyteller_origin",
    heaven: "storyteller_heaven",
    pilgrimage: "storyteller_pilgrimage",
    trials: "storyteller_trials",
    kingdoms: "storyteller_kingdoms",
    arrival: "storyteller_arrival",
  };
  return nodes[arc] || "";
}
var selected = String(board.getVar("tmp_selected_arc") || "");
var arc = selected || "origin";
board.setVar("tmp_story_arc", arc);
board.setVar("tmp_current_arc", storyNode(arc) || "storyteller_origin");

function storyNode(arc) {
  var nodes = {
    origin: "reroute_storyteller_origin",
    heaven: "reroute_storyteller_heaven",
    pilgrimage: "reroute_storyteller_pilgrimage",
    trials: "reroute_storyteller_trials",
    kingdoms: "reroute_storyteller_kingdoms",
    arrival: "reroute_storyteller_arrival",
  };
  return nodes[arc] || "";
}
function firstBeat(arc) {
  var first = {
    origin: "origin.birth",
    heaven: "heaven.summoned",
    pilgrimage: "pilgrimage.rescue",
    trials: "trials.white_bone",
    kingdoms: "kingdoms.daughter_river",
    arrival: "arrival.flame_mountain",
  };
  return first[arc] || "origin.birth";
}
function summary(beat) {
  var summaries = {
    "origin.birth": "石猴从花果山仙石中出世。",
    "origin.waterfall": "石猴进入瀑布，发现水帘洞。",
    "origin.king": "群猴尊石猴为美猴王。",
    "origin.longevity": "美猴王开始担心衰老和死亡，决定寻找长生。",
    "origin.depart": "美猴王离开花果山，漂洋过海寻仙。",
    "origin.find_master": "美猴王漂洋过海，找到灵台方寸山和斜月三星洞。",
    "origin.name": "美猴王初见菩提祖师，祖师给他取名孙悟空。",
    "origin.practice": "孙悟空在洞中做杂活、听讲修心，熬过多年基础功夫。",
    "origin.learn_immortality": "祖师暗中传授孙悟空长生口诀。",
    "origin.learn_transform": "孙悟空学会七十二般变化。",
    "origin.cloud": "孙悟空学会筋斗云。",
    "heaven.summoned": "龙王和地府告上天庭，天庭决定招安孙悟空。",
    "pilgrimage.rescue": "唐三藏在五行山救出孙悟空。",
    "trials.white_bone": "白骨精用假象迷惑唐僧，悟空被误会。",
    "kingdoms.daughter_river": "师徒到女儿国，唐僧和八戒误饮子母河水。",
    "kingdoms.daughter_queen": "女儿国王想留下唐僧成亲，唐僧面对温柔考验。",
    "kingdoms.scorpion": "蝎子精截走唐僧，悟空请昴日星官相助。",
    "kingdoms.chechi": "师徒在车迟国与虎鹿羊三大仙斗法。",
    "kingdoms.biqiu": "比丘国妖道要取小儿心肝，悟空救下孩子。",
    "kingdoms.lion_camel": "狮驼岭三魔势大，师徒经历强妖重压。",
    "arrival.flame_mountain": "师徒来到火焰山，被烈火挡住西行路。",
    "arrival.borrow_fan": "悟空向铁扇公主和牛魔王借芭蕉扇。",
    "arrival.near_lingshan": "师徒越过最后山水，来到灵山脚下。",
    "arrival.scriptures": "师徒拜见如来，先取到无字经又换得真经。",
    "arrival.river_drop": "回程过通天河，老鼋翻身让经卷落水。",
  };
  return summaries[beat] || beat;
}
var arc = String(board.getVar("tmp_reroute_arc") || board.getVar("tmp_route_arc") || "origin");
var requestedBeat = String(board.getVar("tmp_route_beat") || "");
var beat = requestedBeat || firstBeat(arc);
arc = String(beat || "").split(".")[0] || arc;
board.setVar("tmp_story_arc", arc);
board.setVar("tmp_current_arc", storyNode(arc) || "reroute_storyteller_origin");
board.setVar("tmp_target_beat", beat);
board.setVar("tmp_target_summary", summary(beat));

var chapter = board.getVar("current_chapter");
if (typeof chapter !== "number") chapter = 0;
chapter = Math.min(chapter + 1, 7);
board.setVar("current_chapter", chapter);
board.setVar("current_arc", "origin");
board.setVar("last_arc", "origin");

var chapter = board.getVar("current_chapter");
if (typeof chapter !== "number" || chapter < 7) chapter = 7;
chapter = Math.min(chapter + 1, 14);
board.setVar("current_chapter", chapter);
board.setVar("current_arc", "heaven");
board.setVar("last_arc", "heaven");

var chapter = board.getVar("current_chapter");
if (typeof chapter !== "number" || chapter < 14) chapter = 14;
chapter = Math.min(chapter + 1, 27);
board.setVar("current_chapter", chapter);
board.setVar("current_arc", "pilgrimage");
board.setVar("last_arc", "pilgrimage");

var chapter = board.getVar("current_chapter");
if (typeof chapter !== "number" || chapter < 27) chapter = 27;
chapter = Math.min(chapter + 1, 49);
board.setVar("current_chapter", chapter);
board.setVar("current_arc", "trials");
board.setVar("last_arc", "trials");

var chapter = board.getVar("current_chapter");
if (typeof chapter !== "number" || chapter < 49) chapter = 49;
chapter = Math.min(chapter + 1, 74);
board.setVar("current_chapter", chapter);
board.setVar("current_arc", "kingdoms");
board.setVar("last_arc", "kingdoms");

var chapter = board.getVar("current_chapter");
if (typeof chapter !== "number" || chapter < 74) chapter = 74;
chapter = Math.min(chapter + 1, 100);
board.setVar("current_chapter", chapter);
board.setVar("current_arc", "arrival");
board.setVar("last_arc", "arrival");

var state = board.getVar("story_progress_state") || {};
var arc = String(state.arc || board.getVar("tmp_story_arc") || "origin");
var chapter = board.getVar("current_chapter");
if (typeof chapter !== "number") chapter = 0;
if (arc === "arrival") {
  if (chapter < 74) chapter = 74;
  chapter = Math.min(chapter + 1, 100);
  board.setVar("current_chapter", chapter);
} else if (arc === "kingdoms") {
  if (chapter < 49) chapter = 49;
  chapter = Math.min(chapter + 1, 74);
  board.setVar("current_chapter", chapter);
} else if (arc === "trials") {
  if (chapter < 27) chapter = 27;
  chapter = Math.min(chapter + 1, 49);
  board.setVar("current_chapter", chapter);
} else if (arc === "pilgrimage") {
  if (chapter < 14) chapter = 14;
  chapter = Math.min(chapter + 1, 27);
  board.setVar("current_chapter", chapter);
} else if (arc === "heaven") {
  if (chapter < 7) chapter = 7;
  chapter = Math.min(chapter + 1, 14);
  board.setVar("current_chapter", chapter);
} else {
  chapter = Math.min(chapter + 1, 7);
  board.setVar("current_chapter", chapter);
  arc = "origin";
}
board.setVar("current_arc", arc);
board.setVar("last_arc", arc);
